create table tb_order (price float(53), quantity integer, id bigint generated by default as identity, user_id bigint, product_name varchar(255), status varchar(255) check ((status in ('PENDING','PRODUCING','SENDING','DELIVERED'))), primary key (id));
create table tb_role (id bigint generated by default as identity, authority varchar(255) check ((authority in ('RETAIL','PRODUCER'))), primary key (id));
create table tb_user (id bigint generated by default as identity, email varchar(255) unique, name varchar(255), password varchar(255), primary key (id));
create table tb_user_role (role_id bigint not null, user_id bigint not null, primary key (role_id, user_id));
alter table if exists tb_order add constraint FK2p4n9ciui39792tk5qdpcxq1w foreign key (user_id) references tb_user;
alter table if exists tb_user_role add constraint FKea2ootw6b6bb0xt3ptl28bymv foreign key (role_id) references tb_role;
alter table if exists tb_user_role add constraint FK7vn3h53d0tqdimm8cp45gc0kl foreign key (user_id) references tb_user;
